SELECT layer_name, description
FROM layers
ORDER BY layer_name ASC;

SELECT mask_name
FROM masks
WHERE mask_status = 'active';

SELECT DISTINCT pm.patterning_method_name
FROM layers l
JOIN patterning_methods pm ON l.patterning_method_id = pm.patterning_method_id;

SELECT run_id, start_time, end_time
FROM production_runs
WHERE layer_id = (SELECT layer_id FROM layers WHERE layer_name = 'WELL');

SELECT COUNT(*) AS active_masks_count
FROM masks
WHERE mask_status = 'active';

SELECT layer_name
FROM layers
WHERE thickness = (SELECT MAX(thickness) FROM layers);

SELECT layer_name
FROM layers
WHERE layer_name = 'WELL';

SELECT COUNT(*) AS number_of_layers
FROM layers
WHERE lithography = 'EUV' AND patterning = 'SE';
